arguments.argument:
if global.gamePaused=false
{
  if extraHitFrameBuffer>0 {extraHitFrameBuffer-=1}
  
  if atkProg=0
  {
    if type=0
    {
      x+=4
      if x>=room_width-12
      {
        atkProg=1
      }
    }
    else if type=1
    {
      x-=4
      if x<=12
      {
        atkProg=1
      }
    }
  }
  else if atkProg=1
  {
    atkTime+=1
    if atkTime>=30
    {
      image_blend=c_white
      bCanDealDamage=true
      if x>240 {direction=180}
      else {direction=0}
      atkTime=0; atkProg=2
    }
  }
  else if atkProg=2
  {
    speed=bulletSpeed
  }
}
else {speed=0}
